import { test, expect } from '@playwright/test';

test.describe('Authentication Cross-Browser Tests', () => {
  test('should navigate to login page', async ({ page }) => {
    await page.goto('/');
    await page.locator('[data-testid="sign-in-button"]').first().click();
    await expect(page).toHaveURL(/.*login/);
    await expect(page.locator('[data-testid="login-form"]')).toBeVisible();
  });

  test('should validate login form', async ({ page }) => {
    await page.goto('/login');
    await page.locator('[data-testid="login-submit"]').click();
    
    await expect(page.locator('[data-testid="username-error"]')).toContainText('Username is required');
    await expect(page.locator('[data-testid="password-error"]')).toContainText('Password is required');
  });

  test('should handle invalid credentials', async ({ page }) => {
    await page.goto('/login');
    await page.locator('[data-testid="username-input"]').fill('invalid@email.com');
    await page.locator('[data-testid="password-input"]').fill('wrongpassword');
    await page.locator('[data-testid="login-submit"]').click();
    
    await expect(page.locator('[data-testid="error-message"]')).toContainText('Invalid credentials');
  });
});